      assert 2 * (x + y) <= b + c2;
      // Integer arithmetic identity: (b-c2)/2 + c2 == (b+c2)/2
      assert (b - c2) / 2 + c2 == (b + c2) / 2;
    }
    assert x + y <= rem + c2;
  }
